#pragma once
/*
 * Intra-logic block router determines if a candidate packing solution (or intermediate solution) can route.
 *
 * Author: Jason Luu
 * Date: July 22, 2013
 *
 * Updated by Alex Singer, February 2026
 */

#include <cstdio>
#include <queue>
#include <unordered_map>
#include <unordered_set>
#include <vector>
#include "atom_netlist_fwd.h"
#include "atom_pb_bimap.h"
#include "pack_types.h"
#include "vpr_types.h"
#include "vpr_utils.h"

/**************************************************************************
 * Intra-Logic Block Router Data Structures
 ***************************************************************************/

/**
 * @brief Describes the status of a logic cluster_ctx.blocks routing resource
 *        node for a given logic cluster_ctx.blocks instance.
 */
struct t_lb_rr_node_stats {
    /// @brief The number of nets currently using this lb_rr_node.
    int occ;

    /// @brief The mode that this rr_node is set to.
    int mode;

    /// @brief The historical usage of using this node.
    int historical_usage;

    t_lb_rr_node_stats() noexcept {
        occ = 0;
        mode = -1;
        historical_usage = 0;
    }
};

/**
 * @brief Data structure forming the route tree of a net within one logic
 *        cluster_ctx.blocks.
 *
 * A net is implemented using routing resource nodes. The t_lb_trace data
 * structure records one of the nodes used by the net and the connections
 * to other nodes.
 */
struct t_lb_trace {
    /// @brief The current t_lb_type_rr_node used by net.
    int current_node;

    /// @brief The index of previous edge that drives current node.
    std::vector<t_lb_trace> next_nodes;
};

/**
 * @brief Represents a net used inside a logic cluster_ctx.blocks and the
 *        physical nodes used by the net.
 */
struct t_intra_lb_net {
    /// @brief The index of atom net this intra_lb_net represents.
    AtomNetId atom_net_id;

    /// @brief The endpoints of the intra_lb_net, 0th position is the source, all others are sinks.
    std::vector<int> terminals;

    /// @brief The AtomPins associated with each terminal.
    std::vector<AtomPinId> atom_pins;

    /// @brief Marks a terminal as having a fixed target (i.e. a pin not a sink).
    std::vector<bool> fixed_terminals;

    /// @brief Route tree head.
    t_lb_trace rt_tree;

    t_intra_lb_net() noexcept {
        atom_net_id = AtomNetId::INVALID();
        rt_tree.current_node = UNDEFINED;
    }
};

/**
 * @brief Tuning parameters used by intra-logic cluster_ctx.blocks router.
 */
struct t_lb_router_params {
    int max_iterations;
    float pres_fac;
    float pres_fac_mult;
    float hist_fac;
};

/**
 * @brief Node expanded by router.
 */
struct t_expansion_node {
    /// @brief Index of logic cluster_ctx.blocks rr node this expansion node represents.
    int node_index;

    /// @brief Index of logic cluster_ctx.blocks rr node that drives this expansion node.
    int prev_index;

    float cost;

    t_expansion_node() {
        node_index = UNDEFINED;
        prev_index = UNDEFINED;
        cost = 0;
    }
};

/**
 * @brief Comparator used by the priority queue to sort the expansion nodes.
 */
class compare_expansion_node {
  public:
    /**
     * @brief Returns true if e1 comes before e2.
     *
     * Note that because a priority queue outputs the largest element first, the
     * element that "comes before" are actually output last.
     *
     * TL;DR lowest cost is popped first.
     */
    bool operator()(t_expansion_node& e1, t_expansion_node& e2) {
        if (e1.cost > e2.cost) {
            return true;
        }
        return false;
    }
};

/**
 * @brief Explored node by router (trace-back information).
 */
struct t_explored_node_tb {
    /// @brief Previous node that drives this one.
    int prev_index;

    /// @brief ID used to determine if this node has been explored.
    int explored_id;

    /// @brief Net index of route tree.
    int inet;

    /// @brief ID used to determine if this node has been pushed on exploration priority queue.
    int enqueue_id;

    /// @brief Cost of node pushed on exploration priority queue.
    float enqueue_cost;

    t_explored_node_tb() noexcept {
        prev_index = UNDEFINED;
        explored_id = UNDEFINED;
        enqueue_id = UNDEFINED;
        inet = UNDEFINED;
        enqueue_cost = 0;
    }
};

/**
 * @brief Stores status of mode selection during clustering.
 */
struct t_mode_selection_status {
    bool is_mode_conflict = false;
    bool try_expand_all_modes = false;
    bool expand_all_modes = false;

    inline bool is_mode_issue() const {
        return is_mode_conflict || try_expand_all_modes;
    }
};

// TODO: check if this hacky class memory reserve thing is still necessary, if not, then delete
/* Packing uses a priority queue that requires a large number of elements.  This backdoor
 * allows me to use a priority queue where I can pre-allocate the # of elements in the underlying container
 * for efficiency reasons.  Note: Must use vector with this */
template<class T, class U, class V>
class reservable_pq : public std::priority_queue<T, U, V> {
  public:
    typedef typename std::priority_queue<T>::size_type size_type;
    reservable_pq(size_type capacity = 0) {
        reserve(capacity);
        cur_cap = capacity;
    }
    void reserve(size_type capacity) {
        this->c.reserve(capacity);
        cur_cap = capacity;
    }
    void clear() {
        this->c.clear();
        this->c.reserve(cur_cap);
    }

  private:
    size_type cur_cap;
};

/// @brief The priority queue type used in the Cluster Router.
typedef reservable_pq<t_expansion_node, std::vector<t_expansion_node>, compare_expansion_node> ClusterRouterPriorityQueue;

/**
 * @brief Enumeration used by the commit_remove_rt_ method below to decide if
 *        we are committing or removing a route tree.
 */
enum e_commit_remove { RT_COMMIT,
                       RT_REMOVE };

/**
 * @brief Class for routing the connections within a cluster.
 *
 * This class manages all of the state needed to perform pathfinder within a
 * cluster during clustering.
 *
 * Example usage:
 *      // Construct the router object.
 *      ClusterRouter cluster_router(&lb_type_rr_graphs[cluster_type->index], cluster_type);
 *
 *      // Add atoms as targets for the router.
 *      cluster_router.add_atom_as_target(blk_id1, atom_to_pb);
 *      cluster_router.add_atom_as_target(blk_id2, atom_to_pb);
 *      ...
 *
 *      // (optional) Remove atoms from target if necessary
 *      cluster_router.remove_atom_from_target(blk_id1, atom_to_pb);
 *      ...
 *
 *      // Perform a cluster route. success would be true if route is successful.
 *      t_mode_selection_status mode_status;
 *      bool success = cluster_router.try_intra_lb_route(log_verbosity_, &mode_status);
 *
 *      // Output the routing solution.
 *      auto pb_route = cluster_router.alloc_and_load_pb_route(intra_lb_pb_pin_lookup_);
 *
 *      // (optional) Clean the router data to save space if this object will
 *      //            have a long lifetime and no further routes will be performed.
 *      cluster_router.clean_router_data();
 *
 */
class ClusterRouter {
  public:
    /**
     * @brief Default constructor for the ClusterRouter.
     *
     * This is needed to allow this object to be stored within the vtr::vector_map
     * class. When this constructor is used, the cluster router will not be
     * initialized properly and cannot be used.
     */
    ClusterRouter()
        : lb_type_graph_(nullptr)
        , valid_feedback_pins_(nullptr)
        , explore_id_index_(0)
        , lb_type_(nullptr)
        , pres_con_fac_(0.0f)
        , is_clean_(true)
        , is_valid_(false)
        , enable_hot_start_(false) {}

    /**
     * @brief Constructor for the ClusterRouter.
     *
     *  @param lb_type_graph        The RR graph for the given lb type.
     *  @param type                 The logical block type to route to.
     *  @param valid_feedback_pins  Pre-computed set of top-level output pin
     *                              indices with Fc_out > 0; owned by the
     *                              caller and must outlive this router.
     *  @param enable_hot_start     When true, each call to try_intra_lb_route
     *                              seeds unchanged nets from the last successful
     *                              route before running pathfinder, reducing
     *                              the number of nets that need re-routing.
     */
    ClusterRouter(std::vector<t_lb_type_rr_node>* lb_type_graph,
                  t_logical_block_type_ptr type,
                  const std::unordered_set<int>& valid_feedback_pins,
                  bool enable_hot_start = false);

    /**
     * @brief Add pins of netlist atom to current routing drivers/targets.
     */
    void add_atom_as_target(const AtomBlockId blk_id, const AtomPBBimap& atom_to_pb);

    /**
     * @brief Remove pins of netlist atom from current routing drivers/targets.
     */
    void remove_atom_from_target(const AtomBlockId blk_id, const AtomPBBimap& atom_to_pb);

    /**
     * @brief Set/reset mode of rr nodes to the pb used.
     *
     * If set == true, then set all modes of the rr nodes affected by pb to the
     * mode of the pb. Set all modes related to pb to 0 otherwise.
     */
    void set_reset_pb_modes(const t_pb* pb, const bool set);

    /**
     * @brief Attempt to route routing driver/targets on the current architecture.
     *
     * Follows pathfinder negotiated congestion algorithm.
     */
    bool try_intra_lb_route(int verbosity, t_mode_selection_status* mode_status);

    /**
     * @brief Clean and free all data within the router.
     *
     * This is used in the packer to keep the cluster router object around
     * without a hit to memory footprint. The router can no longer be used after
     * this function is called.
     */
    void clean_router_data();

    /**
     * @brief Reset the routing state between calls to intra_lb_route for mode
     *        changes.
     *
     * This is used to clean state associated with mode conflicts in routing.
     * This state is stored within the pb_graph_pins.
     *
     * TODO: It may be safer to store this information internally.
     */
    void reset_intra_lb_route();

    /**
     * @brief Creates an array [0..num_pb_graph_pins-1] for intra-logic block routing lookup.
     * Given a pb_graph_pin ID for a CLB, this lookup returns t_pb_route corresponding to that
     * pin.
     *
     * t_pb_route describes a route for a given atom net in the pb graph. This
     * function returns the t_pb_route for all atom nets within the cluster.
     *
     * @param intra_lb_pb_pin_lookup Intra-logic block pin lookup to get t_pb_graph_pin from a pin ID.
     * @return t_pb_routes An array [0..num_pb_graph_pins-1] for intra-logic block routing lookup.
     */
    t_pb_routes alloc_and_load_pb_route(const IntraLbPbPinLookup& intra_lb_pb_pin_lookup);

    /**
     * @brief Returns true if the saved route from the last successful
     *        try_intra_lb_route is still valid for the current intra_lb_nets_.
     *
     * A saved route is valid when intra_lb_nets_ and saved_lb_nets_ contain
     * exactly the same set of nets with exactly the same terminals. In that
     * case the saved route trees constitute a proven, congestion-free solution
     * for the current cluster state and no re-route is required.
     *
     * This is cheaper than re-running routing and covers the common case where
     * a molecule that failed routing was removed, restoring the cluster to its
     * last successfully-routed state.
     */
    bool is_saved_route_valid() const;

    /**
     * @brief Returns true if the router data has been cleaned.
     */
    inline bool is_clean() const { return is_clean_; }

  private:
    /**
     * @brief Given a pin of a net, assign route tree terminals for it.
     *
     * This assumes that the pin is not already assigned.
     */
    void add_pin_to_rt_terminals_(const AtomPinId pin_id,
                                  const AtomPBBimap& atom_to_pb);

    /**
     * @brief Given a pin of a net, remove route tree terminal from it.
     */
    void remove_pin_from_rt_terminals_(const AtomPinId pin_id,
                                       const AtomPBBimap& atom_to_pb);

    /**
     * @brief Fixup duplicate connections to a net by a logically equivalent
     *        set of primitive pins.
     */
    void fix_duplicate_equivalent_pins_(const AtomPBBimap& atom_to_pb);

    /**
     * @brief Reset the traceback information used in pathfinder.
     */
    void reset_explored_node_tb_();

    /**
     * @brief Commit or remove route tree from currently routed solution.
     */
    void commit_remove_rt_(const t_lb_trace& rt,
                           e_commit_remove op,
                           std::unordered_map<const t_pb_graph_node*, const t_mode*>& mode_map,
                           t_mode_selection_status* mode_status);

    /**
     * @brief Add source node of net as the starting point to existing route tree.
     */
    void add_source_to_rt_(int inet);

    /**
     * @brief Expand all nodes found in route tree into the priority queue.
     *
     *  @param inet     Index into the intra_lb_nets_ to expand to route tree for.
     */
    void expand_rt_(int inet);

    /**
     * @brief Recursive function used by expand_rt_ to expand all nodes in a
     *        route tree into the priority queue.
     */
    void expand_rt_rec_(const t_lb_trace& rt, int prev_index, int irt_net);

    /**
     * @brief Add new path from existing route tree to target sink.
     *
     * This reads the result of the path search to traceback the path and then
     * adds the path to the route tree.
     */
    bool add_to_rt_(t_lb_trace& rt, int node_index, int irt_net);

    /**
     * @brief Expand all nodes for a given lb_net.
     *
     * This method continuously pops from the priority queue to find the best
     * path to the target.
     */
    bool try_expand_nodes_(const t_intra_lb_net& lb_net,
                           t_expansion_node* exp_node,
                           int itarget,
                           bool try_other_modes,
                           int verbosity);

    /**
     * @brief Explore the given node popped from the priority queue and explore
     *        its edges.
     *
     *  @param exp_node                  The node currently being explored.
     *  @param net_fanout                The fanout of the net being routed.
     *  @param target_is_internal_sink   True if the sink we are currently
     *                                   routing toward lives inside this
     *                                   cluster
     */
    void expand_node_(const t_expansion_node& exp_node,
                      int net_fanout,
                      bool target_is_internal_sink);

    /**
     * @brief Explore the given node popped from the priority queue using all
     *        possible modes and explore their edges.
     *
     * This will explore every possible mode that the given node can be in and
     * explore their edges.
     *
     *  @param exp_node                  The node currently being explored.
     *  @param net_fanout                The fanout of the net being routed.
     *  @param target_is_internal_sink   True if the sink we are currently
     *                                   routing toward lives inside this
     *                                   cluster.
     */
    void expand_node_all_modes_(const t_expansion_node& exp_node,
                                int net_fanout,
                                bool target_is_internal_sink);

    /**
     * @brief Explore all edges of an expansion node and insert connected nodes
     *        into the priority queue (i.e. connection routing).
     *
     *  @param mode                      The mode the node that is being explored is in.
     *  @param cur_inode                 The node that is being explored.
     *  @param cur_cost                  The cost of the node that is being explored.
     *  @param net_fanout                The fanout of the net being routed.
     *  @param target_is_internal_sink   True iff the sink is inside this cluster;
     *                                   gates feedback through Fc_out==0 output pins.
     */
    void expand_edges_(int mode,
                       int cur_inode,
                       float cur_cost,
                       int net_fanout,
                       bool target_is_internal_sink);

    /**
     * @brief Determine if a completed route is valid.
     *
     * A successful route has no congestion (i.e. no routing resource is used by
     * two nets).
     */
    bool is_route_success_();

    /**
     * @brief Save the last successful intra-logic block route and reset current
     *        lb_traceback.
     */
    void save_and_reset_lb_route_();

    /**
     * @brief Seed the current routing with route trees from the last successful
     *        route (hot-start).
     *
     * For each saved net whose terminals are unchanged and whose route tree is
     * still valid under the current mode assignments, commits the saved tree
     * into intra_lb_nets_ so that the pathfinder loop can skip those nets on
     * the first iteration via is_skip_route_net.
     *
     * @param mode_map    Mode map updated by commit_remove_rt_ as trees are committed.
     * @param mode_status Mode-selection status updated by commit_remove_rt_.
     */
    void hot_start_intra_lb_route_(
        std::unordered_map<const t_pb_graph_node*, const t_mode*>& mode_map,
        t_mode_selection_status* mode_status);

    /**
     * @brief Debugging function, used to print the description of the given
     *        lb-type RR node.
     */
    std::string describe_lb_type_rr_node_(int inode);

    /**
     * @brief Debugging function, used to print the given congested RR.
     */
    std::string describe_congested_rr_nodes_(const std::vector<int>& congested_rr_nodes);

    /**
     * @brief Debugging function, used to print out the trace of a net.
     */
    void print_trace_(FILE* fp, const t_lb_trace& trace);

    /**
     * @brief Debugging function, print out current intra logic block route.
     */
    void print_route_(const char* filename);

  private:
    // =========================================================================
    // Physical Architecture Info
    // =========================================================================

    /// @brief Pointer to physical intra-logic cluster_ctx.blocks type rr graph.
    std::vector<t_lb_type_rr_node>* lb_type_graph_;

    /// @brief Top-level output pins with Fc_out > 0 for this block type; pointer
    ///        into the map owned by ClusterLegalizer, valid for packing lifetime.
    const std::unordered_set<int>* valid_feedback_pins_;

    // =========================================================================
    // Logical Netlist Info
    // =========================================================================

    /// @brief Vector of intra logic cluster_ctx.blocks nets and their connections.
    std::vector<t_intra_lb_net> intra_lb_nets_;

    /// @brief Save vector of intra logic cluster_ctx.blocks nets and their connections.
    ///        This is used to save the solution for each successful route. This is used
    ///        to allow for other routes to be attempted, while allowing us to roll-back
    ///        to a known-legal routing. This is ultimately used by alloc_and_load_pb_route.
    std::vector<t_intra_lb_net> saved_lb_nets_;

    /// @brief Set that records which atoms are added to cluster router.
    ///        The cluster legalizer will be adding and removing atoms from the
    ///        cluster. This set keeps track of which atoms the Cluster Router is
    ///        aware of being currently in the cluster.
    std::unordered_set<AtomBlockId> atoms_added_;

    // =========================================================================
    // Logical-to-Physical Mapping Info
    // =========================================================================

    /// @brief [0..lb_type_graph->size()-1] Stats for each logic cluster_ctx.blocks rr node instance.
    std::vector<t_lb_rr_node_stats> lb_rr_node_stats_;

    // =========================================================================
    // Stored State Info During Pathfinder Iterative Routing
    // =========================================================================

    /// @brief [0..lb_type_graph->size()-1] Stores mode exploration and lb_traceback info for nodes.
    std::vector<t_explored_node_tb> explored_node_tb_;

    /// @brief Used in conjunction with explored_node_tb_ to determine whether or not a location has been explored.
    ///        By using a unique identifier every route, I don't have to clear the previous route exploration.
    ///        The idea is that for a given route, a specific explore_id is used.
    ///        When exploring nodes, if the ID does not match, we know this is from
    ///        another route. This is just an optimization to prevent clearing the
    ///        global routing data each connection route.
    int explore_id_index_;

    /// @brief The logical block type that is being routed.
    t_logical_block_type_ptr lb_type_;

    /// @brief Parameters used by the router.
    t_lb_router_params params_;

    /// @brief Current congestion factor.
    float pres_con_fac_;

    /// @brief Priority queue used during path search.
    ClusterRouterPriorityQueue pq_;

    /// @brief Flag that indicates if this object has been cleaned or not.
    bool is_clean_;

    /// @brief Flag that indicates if this object has valid state or not. If the
    ///        router is invalid, none of the methods should be used.
    bool is_valid_;

    /// @brief When true, try_intra_lb_route seeds unchanged nets from the last
    ///        successful route before running pathfinder (hot-start).
    bool enable_hot_start_;
};

/**
 * @brief Free the given pb route object.
 */
void free_pb_route(t_pb_route* free_pb_route);

#pragma once
/*
 * Functions to creates, manipulate, and free the lb_type_rr_node graph that represents interconnect within a logic block type.
 *
 * Author: Jason Luu
 * Date: July 22, 2013
 */

#include "pack_types.h"

/* Constructors/Destructors */
std::vector<t_lb_type_rr_node>* alloc_and_load_all_lb_type_rr_graph();
void free_all_lb_type_rr_graph(std::vector<t_lb_type_rr_node>* lb_type_rr_graphs);

/* Accessor functions */
int get_lb_type_rr_graph_ext_source_index(t_logical_block_type_ptr lb_type);
int get_lb_type_rr_graph_ext_sink_index(t_logical_block_type_ptr lb_type);
int get_lb_type_rr_graph_edge_mode(const std::vector<t_lb_type_rr_node>& lb_type_rr_graph, int src_index, int dst_index);

/* Debug functions */
void echo_lb_type_rr_graphs(char* filename, std::vector<t_lb_type_rr_node>* lb_type_rr_graphs);

#pragma once
/**
 * @file
 * @author  Alex Singer
 * @date    September 2024
 * @brief   The declaration of the Cluster Legalizer class.
 *
 * This file declares a class called the ClusterLegalizer which encapsulates all
 * logic for creating legal clusters from prepacked molecules. This class is
 * designed to be self-contained to the point that it is able to be called
 * externally to the Packer in VPR.
 */

#include <optional>
#include <string>
#include <vector>
#include "atom_netlist_fwd.h"
#include "cluster_legalizer_fwd.h"
#include "cluster_router.h"
#include "noc_data_types.h"
#include "partition_region.h"
#include "prepack.h"
#include "vpr_types.h"
#include "vtr_range.h"
#include "vtr_strong_id.h"
#include "vtr_vector.h"
#include "vtr_vector_map.h"
#include "atom_pb_bimap.h"
#include "vpr_utils.h"
#include "packing_signature_tree.h"

// Forward declarations
class Prepacker;
class LogicalModels;
class t_intra_cluster_placement_stats;
class t_pb_graph_node;

/**
 * @brief Holds information to be shared between molecules that represent the
 *        same chained pack pattern, specifically for packing.
 *
 * For example, molecules that are representing a long carry chain that spans
 * multiple logic blocks.
 *
 * This is holding clustering-specific information on the chains. General
 * information on chains is found in the t_chain_info type.
 */
struct t_clustering_chain_info {
    /// @brief An ID into the chain_root_pins vector in the t_pack_patterns of
    ///        the molecule.
    ///
    /// Used to get the starting point of this chain in the cluster. This ID is
    /// useful when we have multiple (architectural) carry chains in a logic
    /// block, for example. It lets us see which of the chains is being used for
    /// this long (netlist) chain, so we continue to use that chain in the
    /// packing of other molecules of this long chain.
    int chain_id = -1;

    /// @brief First molecule to be packed out of the molecules forming this
    ///        chain. This is the molecule setting the value of the chain_id.
    PackMoleculeId first_packed_molecule;
};

/// @brief The different legalization strategies the cluster legalizer can perform.
///
/// Allows the user of the API to select how thorough the legalizer should be
/// when adding molecules into clusters.
enum class ClusterLegalizationStrategy {
    FULL,               // Run the full legalizer (including intra-lb routing)
    SKIP_INTRA_LB_ROUTE // Do all legality checks except intra-lb routing
};

/// @brief The status of the cluster legalization.
enum class e_block_pack_status {
    BLK_PASSED,               // Passed legalization.
    BLK_FAILED_FEASIBLE,      // Failed due to block not feasibly being able to go in the cluster.
    BLK_FAILED_ROUTE,         // Failed due to intra-lb routing failure.
    BLK_FAILED_FLOORPLANNING, // Failed due to not being compatible with the cluster's current PartitionRegion.
    BLK_FAILED_NOC_GROUP,     // Failed due to not being compatible with the cluster's NoC group.
    BLK_STATUS_UNDEFINED      // Undefined status. Something went wrong.
};

/*
 * @brief A struct containing information about the cluster.
 *
 * This contains necessary information for legalizing a cluster.
 */
struct LegalizationCluster {
    /**
     * @brief Default constructor for the LegalizationCluster class.
     *
     * This is needed to use this class within the vtr::vector_map class.
     */
    LegalizationCluster()
        : pb(nullptr)
        , type(nullptr)
        , pr(PartitionRegion())
        , noc_grp_id(NocGroupId::INVALID())
        , cluster_router()
        , placement_stats(nullptr) {}

    /**
     * @brief Constructor for the LegalizationCluster class.
     *
     *  @param cluster_type              The type of this cluster.
     *  @param cluster_mode              The mode of this cluster.
     *  @param lb_type_rr_graphs         The RR-graphs for each cluster type.
     *  @param valid_feedback_pins       Pre-computed feedback-pin set for this type;
     *                                   owned by ClusterLegalizer, must outlive this cluster.
     *  @param enable_router_hot_start   Forwarded to ClusterRouter; enables hot-start
     *                                   routing on each try_intra_lb_route call.
     */
    LegalizationCluster(t_logical_block_type_ptr cluster_type,
                        int cluster_mode,
                        std::vector<t_lb_type_rr_node>* lb_type_rr_graphs,
                        const std::unordered_set<int>& valid_feedback_pins,
                        bool enable_router_hot_start = false);

    /// @brief A list of the molecules in the cluster. By design, a cluster will
    ///        only contain molecules which have been previously legalized into
    ///        the cluster using a legalization strategy.
    std::vector<PackMoleculeId> molecules;

    /// @brief The logical block of this cluster.
    /// TODO: We should be more careful with how this is allocated. Instead of
    ///       pointers, we really should use IDs and store them in a standard
    ///       container. Currently this is being allocated with the new keyword
    ///       and freed when the cluster is destroyed; however this is used
    ///       externally to the class and it can be dangerous to pass around
    ///       a pointer to this object.
    t_pb* pb;

    /// @brief The logical block type this cluster represents.
    t_logical_block_type_ptr type;

    /// @brief The partition region of legal positions this cluster can be placed.
    ///        Used to detect if a molecule can physically be placed in a cluster.
    ///        It is derived from the partition region constraints on the atoms
    ///        in the cluster (not fundamental but good for performance).
    PartitionRegion pr;

    /// @brief The NoC group that this cluster is a part of. Is used to check if
    ///        a candidate primitive is in the same NoC group as the atom blocks
    ///        that have already been added to the primitive. This can be helpful
    ///        for optimization.
    NocGroupId noc_grp_id;

    /// @brief The intra lb router used for this cluster.
    ///        Contains information about the atoms in the cluster and how they
    ///        can be routed within.
    ClusterRouter cluster_router;

    /// @brief The stats on where the different atoms in the cluster are currently
    ///        placed in the cluster. This is used when the legalizer decides
    ///        what sites it should try to put a new molecule into.
    t_intra_cluster_placement_stats* placement_stats;
};

/*
 * @brief A manager class which manages the legalization of clusters. As clusters
 *        are created, this class will legalize for each molecule added. It also
 *        provides methods which are helpful for clustering.
 *
 * Usage:
 * The ClusterLegalizer class maintains the clusters within itself since the
 * legalization of a cluster depends on the molecules which have already been
 * inserted into the clusters prior.
 *
 * The class provides different legalization strategies the user may use to
 * legalize:
 *  1) SKIP_INTRA_LB_ROUTE
 *  2) FULL
 *
 * 1) SKIP_INTRA_LB_ROUTE Legalization Strategy Example:
 * This strategy will not fully route the internal connections of the clusters
 * until when the user specifies. An example of how to use this strategy would
 * look something like this. Note, this example is simplified and the result
 * of the packings should be checked and handled.
 *
 * ClusterLegalizer legalizer(...,
 *                            ClusterLegalizationStrategy::SKIP_INTRA_LB_ROUTE,
 *                            ...);
 *
 * std::tie(status, new_cluster_id) = legalizer.start_new_cluster(seed_mol,
 *                                                                cluster_type,
 *                                                                mode);
 * for mol in molecules_to_add:
 *      // Cheaper additions, but may pack a molecule that wouldn't route.
 *      status = legalizer.add_mol_to_cluster(mol, new_cluster_id);
 *      if (status != e_block_pack_status::BLK_PASSED)
 *          break;
 *
 * // Do the expensive check once all molecules are in.
 * if (!legalizer.check_cluster_legality(new_cluster_id))
 *      // Destroy the illegal cluster.
 *      legalizer.destroy_cluster(new_cluster_id);
 *      // Clean-up the internal bookkeeping of the class (required after
 *      // destroying a cluster).
 *      legalizer.compress();
 *      // Handle how to try again (maybe use FULL strategy).
 *
 * 2) FULL Legalization Strategy Example:
 * This strategy will fully route the internal connections of the clusters for
 * each molecule added. This is much more expensive to run; however, will ensure
 * that the cluster is fully legalized while it is being created. An example
 * of how to use this strategy would look something like this:
 *
 * Clusterlegalizer legalizer(...,
 *                            ClusterLegalizationStrategy::FULL,
 *                            ...);
 *
 * std::tie(pack_result, new_cluster_id) = legalizer.start_new_cluster(seed_mol,
 *                                                                     cluster_type,
 *                                                                     mode);
 * for mol in molecules_to_add:
 *      // Do the expensive check for each molecule added.
 *      status = legalizer.add_mol_to_cluster(mol, new_cluster_id);
 *      if (status != e_block_pack_status::BLK_PASSED)
 *          break;
 *
 * // new_cluster_id now contains a fully legalized cluster.
 */
class ClusterLegalizer {
  public:
    // Iterator for the legalization cluster IDs
    typedef typename vtr::vector_map<LegalizationClusterId, LegalizationClusterId>::const_iterator cluster_iterator;

    // Range for the legalization cluster IDs
    typedef typename vtr::Range<cluster_iterator> cluster_range;

  private:
    /*
     * @brief Helper method that tries to pack the given molecule into a cluster.
     *
     * This method runs all the legality checks specified by the legalization
     * strategy. If the molecule can be packed into the cluster, it will insert
     * it into the cluster.
     *
     *  @param molecule                 The molecule to insert into the cluster.
     *  @param cluster                  The cluster to try to insert the molecule into.
     *  @param cluster_id               The ID of the cluster.
     *  @param max_external_pin_util    The max external pin utilization for a
     *                                  cluster of this type.
     */
    e_block_pack_status try_pack_molecule(PackMoleculeId molecule_id,
                                          LegalizationCluster& cluster,
                                          LegalizationClusterId cluster_id,
                                          const t_ext_pin_util& max_external_pin_util);

    /**
     * @brief This function takes a chain molecule, and the pb_graph_node that is
     *        chosen for packing the molecule's root block. Using the given
     *        root_primitive, this function will identify which chain id this
     *        molecule is being mapped to and will update the chain id value inside
     *        the chain info data structure of this molecule.
     */
    void update_clustering_chain_info(PackMoleculeId chain_molecule_id,
                                      const t_pb_graph_node* root_primitive);

    /*
     * @brief Reset molecule information created while trying to cluster it.
     *
     * This code only resets information that has to do with long chains.
     */
    void reset_molecule_info(PackMoleculeId mol_id);

  public:
    // Explicitly deleted default constructor. Need to use other constructor to
    // initialize state correctly.
    ClusterLegalizer() = delete;

    /*
     * @brief Initialize the ClusterLegalizer class.
     *
     * Allocates internal state.
     *
     *  @param atom_netlist
     *          The complete atom netlist. Used to allocate internal structures
     *          to the correct size.
     *  @param prepacker
     *          The prepacker object used to prepack the atoms into molecules.
     *          A reference to this object is stored internally to be used to
     *          lookup the molecules of atoms.
     *  @param lb_type_rr_graphs
     *          The routing resource graph internal to the different cluster
     *          types. A reference is stored in the class to be used to allocate
     *          and load the router data.
     *  @param target_external_pin_util_str
     *          A string used to initialize the target external pin utilization
     *          of each cluster type.
     *  @param high_fanout_thresholds
     *          An object that stores the thresholds for a net to be considered
     *          high fanout for different block types.
     *  @param cluster_legalization_strategy
     *          The legalization strategy to be used when creating clusters and
     *          adding molecules to clusters. Controls the checks that are
     *          performed.
     *  @param enable_pin_feasibility_filter
     *          A flag to turn on/off the check for pin usage feasibility.
     *  @param memoize_cluster_packings
     *          A flag to turn on/off the cluster memoization runtime optimization.
     *  @param enable_cluster_router_hot_start
     *          When true, each call to try_intra_lb_route seeds unchanged nets
     *          from the last successful route before running pathfinder.
     *  @param models
     *  @param log_verbosity
     *          Controls how verbose the log messages will be within this class.
     */
    ClusterLegalizer(const AtomNetlist& atom_netlist,
                     const Prepacker& prepacker,
                     std::vector<t_lb_type_rr_node>* lb_type_rr_graphs,
                     const std::vector<std::string>& target_external_pin_util_str,
                     const t_pack_high_fanout_thresholds& high_fanout_thresholds,
                     ClusterLegalizationStrategy cluster_legalization_strategy,
                     bool enable_pin_feasibility_filter,
                     bool memoize_cluster_packings,
                     bool enable_cluster_router_hot_start,
                     const LogicalModels& models,
                     int log_verbosity);

    // This class allocates and deallocates memory within. This class should not
    // be copied or moved to prevent it from double freeing / losing pointers.
    ClusterLegalizer(const ClusterLegalizer&) = delete;
    ClusterLegalizer& operator=(const ClusterLegalizer&) = delete;

    /*
     * @brief Start a new legalization cluster with the given molecule.
     *
     *  @param molecule         The seed molecule used to start the new cluster.
     *  @param cluster_type     The type of the cluster to start.
     *  @param cluster_mode     The mode of the new cluster for the given type.
     *
     *  @return     A pair for the status of the packing and the ID of the new
     *              cluster. If the new cluster could not be created, the pack
     *              status will return the reason and the ID would be invalid.
     */
    std::tuple<e_block_pack_status, LegalizationClusterId>
    start_new_cluster(PackMoleculeId molecule_id,
                      t_logical_block_type_ptr cluster_type,
                      int cluster_mode);

    /*
     * @brief Add an unclustered molecule to the given legalization cluster.
     *
     * The ClusterLegalizationStrategy (set either in the constructor or by the
     * set_cluster_legalization_strategy method) decides what checks are
     * performed when adding a molecule to the cluster.
     *
     * If the addition was unsuccessful (i.e. a check fails), the molecule will
     * remain unclustered.
     *
     *  @param molecule         The molecule to add to the cluster.
     *  @param cluster_id       The ID of the cluster to add the molecule to.
     *
     *  @return     The status of the pack (if the addition was successful and
     *              if not why).
     */
    e_block_pack_status add_mol_to_cluster(PackMoleculeId molecule_id,
                                           LegalizationClusterId cluster_id);

    /*
     * @brief Destroy the given cluster.
     *
     * This unclusters all molecules in the cluster so they can be re-clustered
     * into different clusters. Should call the compress() method after destroying
     * one or more clusters.
     *
     *  @param cluster_id       The ID of the cluster to destroy.
     */
    void destroy_cluster(LegalizationClusterId cluster_id);

    /*
     * @brief Compress the internal storage of clusters. Should be called
     *        eventually after one or more clusters are destroyed.
     *
     * Similar to the Netlist compress method. Will invalidate all Legalization
     * Cluster IDs.
     *
     * This method can be quite expensive, so it is a good idea to batch many
     * cluster destructions and then compress at the end.
     */
    void compress();

    /*
     * @brief A range of all cluster IDs in the legalizer.
     *
     * If the legalizer has been compressed (or no clusters have been destroyed)
     * then all cluster IDs in this list will be valid and represent a non-empty
     * legalization cluster.
     */
    cluster_range clusters() const {
        return vtr::make_range(legalization_cluster_ids_.begin(), legalization_cluster_ids_.end());
    }

    /*
     * @brief Check that the given cluster is fully legal.
     *
     * This method runs an intra_lb_route on the given cluster. This ignores
     * the cluster legalization strategy set by the user. This method will not
     * correct the problematic molecules, it will only return true if the
     * cluster is legal and false if it is not.
     *
     *  @param cluster_id       The ID of the cluster to fully legalize.
     *
     *  @return                 True if the cluster is legal, false otherwise.
     */
    bool check_cluster_legality(LegalizationClusterId cluster_id);

    /*
     * @brief Ensure that the cluster has a legal final routing.
     *
     * Checks that the cluster is routable. If it is routable, ensures that
     * an up-to-date routing has been created and stored in the appropriate
     * clustering data structures, creating one if not.
     *
     * For SKIP_INTRA_LB_ROUTE packing, this is the first time routing
     * is run on the cluster and may fail. For detailed routing with the
     * the PackingSignatureTree enabled, this function makes sure the cluster
     * has a routing to pass to later stages since routing steps may have been
     * skipped for cluster patterns where the legality was known from packing
     * a previous cluster.
     *
     *  @param cluster_id       The ID of the cluster to ensure has a legal routing.
     *
     *  @return                 True if the cluster is routed and legal, false otherwise.
     * */
    bool ensure_legal_final_routing(LegalizationClusterId cluster_id);

    /*
     * @brief Cleans the cluster of unnecessary data, reducing the memory footprint.
     *
     * After this function is called, no more molecules can be added to the
     * cluster. This method will ensure that the cluster has enough information
     * to generate a clustered netlist from the legalized clusters.
     *
     * Specifically, this frees the pb stats (which is used by the clusterer
     * to compute the gain) and the router data of the cluster.
     *
     * TODO: The pb stats should really not be calculated or stored in the
     *       cluster legalizer.
     *
     *  @param cluster_id   The ID of the cluster to clean.
     */
    void clean_cluster(LegalizationClusterId cluster_id);

    /*
     * @brief Verify that all atoms have been clustered into some cluster.
     *
     * This will not verify if all the clusters are fully legal.
     */
    void verify();

    /*
     * @brief Finalize the clustering. Required for generating a Clustered
     *        Netlist.
     *
     * Before generating a Clustered Netlist, each cluster needs to allocate and
     * load a pb_route. This method will generate a pb_route for each cluster
     * and store it into the clusters' pb.
     */
    void finalize();

    /*
     * @brief Resets the legalizer to its initial state.
     *
     * Destroys all clusters and resets the cluster placement stats.
     */
    void reset();

    /*
     * @brief Checks if the given molecule is compatible with the given cluster.
     *
     * A molecule is compatible with a cluster if there exists a free primitive
     * (a primitive that is not currently occupied by other atoms) of the correct
     * type to accommodate each type of atom in the molecule.
     *
     * This is a quick check to see if a molecule can go in the given cluster.
     * "This is a necessary but not sufficient test for a molecule to be able to
     * go in a cluster. By calling it you can save runtime for impossible cases
     * vs. calling the full checks.
     */
    bool is_molecule_compatible(PackMoleculeId molecule_id,
                                LegalizationClusterId cluster_id) const;

    /// @brief Gets the top-level pb of the given cluster.
    inline t_pb* get_cluster_pb(LegalizationClusterId cluster_id) const {
        VTR_ASSERT_SAFE(cluster_id.is_valid() && (size_t)cluster_id < legalization_clusters_.size());
        const LegalizationCluster& cluster = legalization_clusters_[cluster_id];
        return cluster.pb;
    }

    /// @brief Gets the name of the given cluster.
    inline std::string get_cluster_name(LegalizationClusterId cluster_id) const {
        VTR_ASSERT_SAFE(cluster_id.is_valid() && (size_t)cluster_id < legalization_clusters_.size());
        const LegalizationCluster& cluster = legalization_clusters_[cluster_id];
        return cluster.pb->name;
    }

    /// @brief Gets the logical block type of the given cluster.
    inline t_logical_block_type_ptr get_cluster_type(LegalizationClusterId cluster_id) const {
        VTR_ASSERT_SAFE(cluster_id.is_valid() && (size_t)cluster_id < legalization_clusters_.size());
        const LegalizationCluster& cluster = legalization_clusters_[cluster_id];
        return cluster.type;
    }

    /// @brief Gets the current partition region (the intersection of all
    ///        contained atoms) of the given cluster.
    inline const PartitionRegion& get_cluster_pr(LegalizationClusterId cluster_id) const {
        VTR_ASSERT_SAFE(cluster_id.is_valid() && (size_t)cluster_id < legalization_clusters_.size());
        const LegalizationCluster& cluster = legalization_clusters_[cluster_id];
        return cluster.pr;
    }

    /// @brief Gets the molecules currently packed within the given cluster.
    inline const std::vector<PackMoleculeId>& get_cluster_molecules(LegalizationClusterId cluster_id) const {
        VTR_ASSERT_SAFE(cluster_id.is_valid() && (size_t)cluster_id < legalization_clusters_.size());
        const LegalizationCluster& cluster = legalization_clusters_[cluster_id];
        return cluster.molecules;
    }

    /// @brief Gets the current number of molecules in the cluster.
    inline size_t get_num_molecules_in_cluster(LegalizationClusterId cluster_id) const {
        VTR_ASSERT_SAFE(cluster_id.is_valid() && (size_t)cluster_id < legalization_clusters_.size());
        const LegalizationCluster& cluster = legalization_clusters_[cluster_id];
        return cluster.molecules.size();
    }

    /// @brief Gets the total number of cluster inputs available.
    size_t get_num_cluster_inputs_available(LegalizationClusterId cluster_id) const;

    /// @brief Gets the ID of the cluster that contains the given atom block.
    inline LegalizationClusterId get_atom_cluster(AtomBlockId blk_id) const {
        VTR_ASSERT_SAFE(blk_id.is_valid() && (size_t)blk_id < atom_cluster_.size());
        return atom_cluster_[blk_id];
    }

    /// @brief Returns true if the given atom block has been packed into a
    ///        cluster, false otherwise.
    inline bool is_atom_clustered(AtomBlockId blk_id) const {
        // Simply, if the atom is not in an invalid cluster, it has been clustered.
        return get_atom_cluster(blk_id) != LegalizationClusterId::INVALID();
    }

    /// @brief Returns true if the given molecule has been packed into a
    ///        cluster, false otherwise.
    inline bool is_mol_clustered(PackMoleculeId mol_id) const {
        VTR_ASSERT_SAFE(mol_id.is_valid());
        // Check if the molecule has been assigned a cluster. It has not been
        // assigned a cluster if it is assigned to a valid cluster.
        return molecule_cluster_[mol_id].is_valid();
    }

    /// @brief Returns a reference to the target_external_pin_util object. This
    ///        allows the user to modify the external pin utilization if needed.
    inline t_ext_pin_util_targets& get_target_external_pin_util() {
        return target_external_pin_util_;
    }

    /*
     * @brief Set the legalization strategy of the cluster legalizer.
     *
     * This allows the strategy of the cluster legalizer to change based on the
     * needs of the user. For example, one can set the legalizer to use a more
     * relaxed strategy to insert a batch of molecules in cheaply, saving the
     * full legalizerion for the end (using check_cluster_legality).
     *
     *  @param strategy     The strategy to set the cluster legalizer to.
     */
    inline void set_legalization_strategy(ClusterLegalizationStrategy strategy) {
        cluster_legalization_strategy_ = strategy;
    }

    /*
     * @brief Set how verbose the log messages should be for the cluster legalizer.
     *
     * This allows the user to set the verbosity at different points for easier
     * usability.
     *
     * Set the verbosity to 4 to see most of the log messages on how the
     * molecules move through the legalizer.
     * Set the verbosity to 5 to see all the log messages in the legalizer.
     *
     *  @param verbosity    The value to set the verbosity to.
     */
    inline void set_log_verbosity(int verbosity) {
        log_verbosity_ = verbosity;
    }

    inline const AtomPBBimap& atom_pb_lookup() const { return atom_pb_lookup_; }
    inline AtomPBBimap& mutable_atom_pb_lookup() { return atom_pb_lookup_; }

    inline const IntraLbPbPinLookup& intra_lb_pb_pin_lookup() const { return intra_lb_pb_pin_lookup_; }

    /// @brief Destructor of the class. Frees allocated data.
    ~ClusterLegalizer();

  private:
    /// @brief Build the per-type feedback-pin sets used by the intra-cluster router.
    ///        Called once by the constructor.
    void init_feedback_pin_sets();

    /// @brief A vector of the legalization cluster IDs. If any of them are
    ///        invalid, then that means that the cluster has been destroyed.
    vtr::vector_map<LegalizationClusterId, LegalizationClusterId> legalization_cluster_ids_;

    /// @brief Lookup table for which cluster each molecule is in.
    vtr::vector_map<PackMoleculeId, LegalizationClusterId> molecule_cluster_;

    /// @brief Clustering chain information for each of the chains in the prepacker.
    vtr::vector_map<MoleculeChainId, t_clustering_chain_info> clustering_chain_info_;

    /// @brief List of all legalization clusters.
    vtr::vector_map<LegalizationClusterId, LegalizationCluster> legalization_clusters_;

    /// @brief A lookup-table for which cluster the given atom is packed into.
    vtr::vector_map<AtomBlockId, LegalizationClusterId> atom_cluster_;

    /// @brief Stores the NoC group ID of each atom block. Atom blocks that
    ///        belong to different NoC groups can't be clustered with each other
    ///        into the same clustered block. Under some optimization settings
    ///        to improve placement locality / NoC usage. Atoms with different
    ///        NoC group IDs belong to logic that is disjoint except through
    ///        NoC traffic.
    vtr::vector<AtomBlockId, NocGroupId> atom_noc_grp_id_;

    /// @brief The maximum fractional utilization of cluster external
    ///        input/output pins during packing (between 0 and 1).
    t_ext_pin_util_targets target_external_pin_util_;

    /// @brief The max size of any molecule. This is used to allocate a dynamic
    ///        array within the legalizer, and in its current form this is a bit
    ///        expensive to calculate from the prepacker.
    size_t max_molecule_size_;

    /// @brief A vector of routing resource nodes within each logical block type
    ///        [0 .. num_logical_block_types-1]
    /// TODO: This really should not be a pointer to a vector... I think this is
    ///       meant to be a vector of vectors...
    std::vector<t_lb_type_rr_node>* lb_type_rr_graphs_ = nullptr;

    /// @brief Per-type set of top-level output pin indices with Fc_out > 0.
    ///        Indexed by t_logical_block_type::index.
    std::vector<std::unordered_set<int>> valid_feedback_pins_by_type_;

    /// @brief The current legalization strategy of the cluster legalizer.
    ClusterLegalizationStrategy cluster_legalization_strategy_;

    /// @brief Controls whether the pin counting feasibility filter is used
    ///        during clustering. When enabled the clustering engine counts the
    ///        number of available pins in groups/classes of mutually connected
    ///        pins within a cluster. These counts are used to quickly filter
    ///        out candidate primitives/atoms/molecules for which the cluster
    ///        has insufficient pins to route (without performing a full
    ///        routing). This reduces packing run-time. This matches the packer
    ///        option of the same name.
    bool enable_pin_feasibility_filter_;

    /// @brief When true, each ClusterRouter seeds unchanged nets from the last
    ///        successful route before running pathfinder (hot-start). Matches
    ///        the --cluster_router_hot_start packer option.
    bool enable_cluster_router_hot_start_;

    /// @brief Used to set the verbosity of log messages in the legalizer. Used
    ///        for debugging. When log_verbosity > 3, the legalizer will print
    ///        messages when a molecule is successful during legalization. When
    ///        log_verbosity is > 4, the legalizer will print when a molecule
    ///        fails a legality check. This parameter is also passed into the
    ///        intra-lb router.
    int log_verbosity_;

    /// @brief The prepacker object that stores the molecules which will be
    ///        legalized into clusters.
    const Prepacker& prepacker_;

    /// @brief A two way map between AtomBlockIds and pb types. This is a copy
    /// of the AtomPBBimap in the global context's AtomLookup
    AtomPBBimap atom_pb_lookup_;

    /// @brief A lookup table for the pin mapping of the intra-lb pb pins.
    IntraLbPbPinLookup intra_lb_pb_pin_lookup_;

    /// @brief A structure for tracking and identifying cluster packing
    ///        patterns that have been previously tested for routing
    ///        feasibility. Cluster legality check results are memoized and
    ///        reused to avoid repeating work.
    std::optional<PackingSignatureTree> packing_signature_tree_;
};

/**
 * @brief Check that the two atom blocks blk_id and sibling_blk_id (which should
 *        both be memory slices) are feasible, in the sense that they have
 *        precisely the same net connections (with the exception of nets in data
 *        port classes).
 *
 * Note that this routine does not check pin feasibility against the cur_pb_type, so
 * primitive_type_feasible() should also be called on blk_id before concluding it is feasible.
 *
 * @param blk_id          The atom block being checked for sibling feasibility.
 * @param cur_pb_type     The primitive type to check net connections against.
 * @param sibling_blk_id  The sibling atom to compare net connections with.
 * @return                True if the two blocks are sibling-feasible.
 */
bool primitive_memory_sibling_feasible(const AtomBlockId blk_id, const t_pb_type* cur_pb_type, const AtomBlockId sibling_blk_id);

