1	/*
2	 * Creates a lb_type_rr_node graph to represent interconnect within a logic block type.
3	 *
4	 * For a given logic block, the internal routing resource graph is constructed as follows:
5	 * Each pb_graph_pin is a node in this graph and is indexed by the pin number of the pb_graph pin
6	 * External nets that drive into the logic block come from one source indexed by the total number of pins
7	 * External nets that the logic block drives are represented as one sink indexed by the total number of pins + 1
8	 * Each primitive input pin drives a sink.  Since the input pin has a corresponding lb_type_rr_node, the sink node driven by
9	 * the pin must have a different index.  I append these sinks to the end of the vector.
10	 * Each primitive output pin is a source.
11	 *
12	 * Common acryonyms:
13	 * rr - routing resource
14	 * lb - logic block
15	 * pb - physical block (the top level physical block is the logic block, a leaf physical block is a primitive)
16	 *
17	 * Author: Jason Luu
18	 * Date: July 22, 2013
19	 */
20	
21	#include <cstdio>
22	#include <cstring>
23	#include <vector>
24	#include <cmath>
25	
26	#include "vpr_utils.h"
27	#include "vtr_assert.h"
28	
29	#include "vtr_util.h"
30	#include "physical_types.h"
31	#include "vpr_types.h"
32	#include "globals.h"
33	#include "pack_types.h"
34	#include "lb_type_rr_graph.h"
35	
36	/*****************************************************************************************
37	 * Internal functions declarations
38	 ******************************************************************************************/
39	static void alloc_and_load_lb_type_rr_graph_for_type(const t_logical_block_type_ptr lb_type,
40	                                                     std::vector<t_lb_type_rr_node>& lb_type_rr_node_graph);
