51	/* Populate each logic block type (type_descriptor) with a directed graph that represents the interconnect within it.
52	 */
53	std::vector<t_lb_type_rr_node>* alloc_and_load_all_lb_type_rr_graph() {
54	    std::vector<t_lb_type_rr_node>* lb_type_rr_graphs;
55	    auto& device_ctx = g_vpr_ctx.device();
56	
57	    lb_type_rr_graphs = new std::vector<t_lb_type_rr_node>[device_ctx.logical_block_types.size()];
58	
59	    for (const auto& type : device_ctx.logical_block_types) {
60	        int itype = type.index;
61	        if (&type != device_ctx.EMPTY_LOGICAL_BLOCK_TYPE) {
62	            alloc_and_load_lb_type_rr_graph_for_type(&type, lb_type_rr_graphs[itype]);
63	
64	            /* Now that the data is loaded, reallocate to the precise amount of memory needed to prevent insidious bugs */
65	            /* I should be using shrinktofit() but as of 2013, C++ 11 is yet not well supported so I can't call this function in gcc */
66	            std::vector<t_lb_type_rr_node>(lb_type_rr_graphs[itype]).swap(lb_type_rr_graphs[itype]);
67	        }
68	    }
69	    return lb_type_rr_graphs;
70	}
