72	/* Free routing resource graph for all logic block types */
73	void free_all_lb_type_rr_graph(std::vector<t_lb_type_rr_node>* lb_type_rr_graphs) {
74	    if (lb_type_rr_graphs == nullptr) {
75	        return;
76	    }
77	
78	    auto& device_ctx = g_vpr_ctx.device();
79	
80	    for (const auto& type : device_ctx.logical_block_types) {
81	        int itype = type.index;
82	        if (!is_empty_type(&type)) {
83	            int graph_size = lb_type_rr_graphs[itype].size();
84	            for (int inode = 0; inode < graph_size; inode++) {
85	                t_lb_type_rr_node* node = &lb_type_rr_graphs[itype][inode];
86	                if (node->outedges != nullptr) {
87	                    for (int imode = 0; imode < node->num_modes; imode++) {
88	                        if (node->outedges[imode] != nullptr) {
89	                            delete[] node->outedges[imode];
90	                        }
91	                    }
92	                    delete[] node->outedges;
93	                }
94	                if (node->num_fanout != nullptr) {
95	                    delete[] node->num_fanout;
96	                }
97	            }
98	        }
99	    }
100	    delete[] lb_type_rr_graphs;
101	}
