117	int get_lb_type_rr_graph_edge_mode(const std::vector<t_lb_type_rr_node>& lb_type_rr_graph, int src_index, int dst_index) {
118	    auto& src = lb_type_rr_graph[src_index];
119	    for (int imode = 0; imode < src.num_modes; imode++) {
120	        for (int iedge = 0; iedge < src.num_fanout[imode]; iedge++) {
