156	/* Given a logic block type, build its internal routing resource graph
157	 * Each pb_graph_pin has a corresponding lb_type_rr_node that is indexed by the pin index of that pb_graph_pin
158	 * Extra sources and sinks in lb_type_rr_node_graph that do not correspond to a pb_graph_pin are appended in indices following total_pb_pins
159	 * of the pb_type
160	 */
161	static void alloc_and_load_lb_type_rr_graph_for_type(const t_logical_block_type_ptr lb_type,
162	                                                     std::vector<t_lb_type_rr_node>& lb_type_rr_node_graph) {
163	    t_pb_type* pb_type;
164	    t_pb_graph_node* pb_graph_head;
165	    int ext_source_index, ext_sink_index, ext_rr_index;
166	    int ioutedges;
167	
168	    VTR_ASSERT(lb_type_rr_node_graph.empty());
169	
170	    pb_type = lb_type->pb_type;
171	    pb_graph_head = lb_type->pb_graph_head;
172	
173	    /* Indices [0..total_pb_pins - 1] have a 1-to-1 matching with a pb_graph_pin
174	     * Index total_pb_pins represents all external sources to logic block type
175	     * Index total_pin_pins + 1 represents all external sinks from logic block type
176	     * Index total_pin_pins + 2 represents feedback connections from external rr graph back into cluster
177	     * All nodes after total_pin_pins + 2 are other nodes that do not have a corresponding pb_graph_pin (eg. a sink node that is driven by one or more pb_graph_pins of a primitive)
178	     */
179	    lb_type_rr_node_graph.resize(pb_graph_head->total_pb_pins + 3);
180	
181	    /* Define the external source, sink, and external interconnect for the routing resource graph of the logic block type */
182	    ext_source_index = pb_graph_head->total_pb_pins;
183	    ext_sink_index = pb_graph_head->total_pb_pins + 1;
184	    ext_rr_index = pb_graph_head->total_pb_pins + 2;
185	
186	    VTR_ASSERT(lb_type_rr_node_graph[ext_source_index].type == NUM_LB_RR_TYPES && lb_type_rr_node_graph[ext_sink_index].type == NUM_LB_RR_TYPES);
187	
188	    /*******************************************************************************
189	     * Build logic block source node
190	     *******************************************************************************/
191	
192	    /* External source node drives all inputs going into logic block type */
193	    lb_type_rr_node_graph[ext_source_index].capacity = pb_type->num_input_pins + pb_type->num_clock_pins;
194	    lb_type_rr_node_graph[ext_source_index].num_modes = 1;
195	    lb_type_rr_node_graph[ext_source_index].num_fanout = new short[1];
196	    lb_type_rr_node_graph[ext_source_index].num_fanout[0] = pb_type->num_input_pins + pb_type->num_clock_pins;
197	    lb_type_rr_node_graph[ext_source_index].outedges = new t_lb_type_rr_node_edge*[1];
198	    lb_type_rr_node_graph[ext_source_index].outedges[0] = nullptr;
199	    if (lb_type_rr_node_graph[ext_source_index].num_fanout[0] > 0) {
200	        lb_type_rr_node_graph[ext_source_index].outedges[0] = new t_lb_type_rr_node_edge[lb_type_rr_node_graph[ext_source_index].num_fanout[0]];
201	        for (int i = 0; i < lb_type_rr_node_graph[ext_source_index].num_fanout[0]; i++)
202	            lb_type_rr_node_graph[ext_source_index].outedges[0][i] = t_lb_type_rr_node_edge();
203	    }
204	    lb_type_rr_node_graph[ext_source_index].type = LB_SOURCE;
205	
206	    /* Connect external source node to all input and clock pins of logic block type */
207	    ioutedges = 0;
208	
209	    for (int iport = 0; iport < pb_graph_head->num_input_ports; iport++) {
210	        for (int ipin = 0; ipin < pb_graph_head->num_input_pins[iport]; ipin++) {
211	            lb_type_rr_node_graph[ext_source_index].outedges[0][ioutedges].node_index = pb_graph_head->input_pins[iport][ipin].pin_count_in_cluster;
212	            lb_type_rr_node_graph[ext_source_index].outedges[0][ioutedges].intrinsic_cost = 1;
213	            ioutedges++;
214	        }
215	    }
216	
217	    for (int iport = 0; iport < pb_graph_head->num_clock_ports; iport++) {
218	        for (int ipin = 0; ipin < pb_graph_head->num_clock_pins[iport]; ipin++) {
219	            lb_type_rr_node_graph[ext_source_index].outedges[0][ioutedges].node_index = pb_graph_head->clock_pins[iport][ipin].pin_count_in_cluster;
220	            lb_type_rr_node_graph[ext_source_index].outedges[0][ioutedges].intrinsic_cost = 1;
221	            ioutedges++;
222	        }
223	    }
224	
225	    /* Check that the fanout indices are correct */
226	    VTR_ASSERT(ioutedges == pb_type->num_input_pins + pb_type->num_clock_pins);
227	
228	    /*******************************************************************************
229	     * Build logic block sink node
230	     *******************************************************************************/
231	
232	    /* External sink node driven by all outputs exiting logic block type */
233	    lb_type_rr_node_graph[ext_sink_index].capacity = pb_type->num_output_pins;
234	    lb_type_rr_node_graph[ext_sink_index].num_modes = 1;
235	    lb_type_rr_node_graph[ext_sink_index].num_fanout = new short[1];
236	    lb_type_rr_node_graph[ext_sink_index].num_fanout[0] = 0; /* Terminal point */
237	    lb_type_rr_node_graph[ext_sink_index].outedges = nullptr;
238	    lb_type_rr_node_graph[ext_sink_index].type = LB_SINK;
239	
240	    /*******************************************************************************
241	     * Build node that approximates external interconnect
242	     *******************************************************************************/
243	
244	    /* External rr node that drives all existing logic block input pins and is driven by all outputs exiting logic block type */
245	    lb_type_rr_node_graph[ext_rr_index].capacity = pb_type->num_output_pins;
246	    lb_type_rr_node_graph[ext_rr_index].num_modes = 1;
247	    lb_type_rr_node_graph[ext_rr_index].num_fanout = new short[1];
248	    lb_type_rr_node_graph[ext_rr_index].num_fanout[0] = pb_type->num_input_pins + pb_type->num_clock_pins + 1;
249	    lb_type_rr_node_graph[ext_rr_index].outedges = new t_lb_type_rr_node_edge*[1];
250	    lb_type_rr_node_graph[ext_rr_index].outedges[0] = nullptr;
251	    if (lb_type_rr_node_graph[ext_rr_index].num_fanout[0] > 0) {
252	        lb_type_rr_node_graph[ext_rr_index].outedges[0] = new t_lb_type_rr_node_edge[lb_type_rr_node_graph[ext_rr_index].num_fanout[0]];
253	        for (int i = 0; i < lb_type_rr_node_graph[ext_rr_index].num_fanout[0]; i++)
254	            lb_type_rr_node_graph[ext_rr_index].outedges[0][i] = t_lb_type_rr_node_edge();
255	    }
256	    lb_type_rr_node_graph[ext_rr_index].type = LB_INTERMEDIATE;
257	
258	    /* Connect opin of logic block to sink */
259	    lb_type_rr_node_graph[ext_rr_index].outedges[0][0].node_index = ext_sink_index;
260	    lb_type_rr_node_graph[ext_rr_index].outedges[0][0].intrinsic_cost = 1;
261	
262	    /* Connect opin of logic block to all input and clock pins of logic block type */
263	    ioutedges = 1;
264	    for (int iport = 0; iport < pb_graph_head->num_input_ports; iport++) {
265	        for (int ipin = 0; ipin < pb_graph_head->num_input_pins[iport]; ipin++) {
266	            lb_type_rr_node_graph[ext_rr_index].outedges[0][ioutedges].node_index = pb_graph_head->input_pins[iport][ipin].pin_count_in_cluster;
267	            lb_type_rr_node_graph[ext_rr_index].outedges[0][ioutedges].intrinsic_cost = 1000; /* set cost high to avoid using external interconnect unless necessary */
268	            ioutedges++;
269	        }
270	    }
271	    for (int iport = 0; iport < pb_graph_head->num_clock_ports; iport++) {
272	        for (int ipin = 0; ipin < pb_graph_head->num_clock_pins[iport]; ipin++) {
273	            lb_type_rr_node_graph[ext_rr_index].outedges[0][ioutedges].node_index = pb_graph_head->clock_pins[iport][ipin].pin_count_in_cluster;
274	            lb_type_rr_node_graph[ext_rr_index].outedges[0][ioutedges].intrinsic_cost = 1000; /* set cost high to avoid using external interconnect unless necessary */
275	            ioutedges++;
276	        }
277	    }
278	
279	    alloc_and_load_lb_type_rr_graph_for_pb_graph_node(pb_graph_head, lb_type_rr_node_graph, ext_rr_index);
280	}
281	
282	/* Given a pb_graph_node, build the routing resource data for it.
283	 * Each pb_graph_pin has a corresponding rr node.  This rr node is indexed by the pb_graph_pin pin index.
284	 * This function populates the rr node for the pb_graph_pin of the current pb_graph_node then recursively
285	 * repeats this on all children of the pb_graph_node
286	 */
287	static void alloc_and_load_lb_type_rr_graph_for_pb_graph_node(const t_pb_graph_node* pb_graph_node,
288	                                                              std::vector<t_lb_type_rr_node>& lb_type_rr_node_graph,
289	                                                              const int ext_rr_index) {
290	    t_pb_type* pb_type;
291	    int pin_index;
292	    t_pb_graph_pin* pb_pin;
293	    t_pb_graph_node* parent_node;
294	
295	    pb_type = pb_graph_node->pb_type;
296	    parent_node = pb_graph_node->parent_pb_graph_node;
297	    int num_modes;
298	
299	    if (pb_type->is_primitive()) {
300	        /* This pb_graph_node is a terminating leaf node (primitive) */
301	
302	        /* alloc and load input pins that connect to sinks */
303	        for (int iport = 0; iport < pb_graph_node->num_input_ports; iport++) {
304	            PortEquivalence port_equivalent = PortEquivalence::NONE;
305	            int sink_index = UNDEFINED;
306	            for (int ipin = 0; ipin < pb_graph_node->num_input_pins[iport]; ipin++) {
307	                /* load intermediate indices */
308	                pb_pin = &pb_graph_node->input_pins[iport][ipin];
309	                port_equivalent = pb_pin->port->equivalent;
310	                pin_index = pb_pin->pin_count_in_cluster;
311	
312	                /* alloc and load rr node info */
313	                lb_type_rr_node_graph[pin_index].capacity = 1;
314	                lb_type_rr_node_graph[pin_index].num_modes = 1;
315	                lb_type_rr_node_graph[pin_index].num_fanout = new short[1];
316	                lb_type_rr_node_graph[pin_index].num_fanout[0] = 1;
317	                lb_type_rr_node_graph[pin_index].outedges = new t_lb_type_rr_node_edge*[1];
318	                lb_type_rr_node_graph[pin_index].outedges[0] = nullptr;
319	                lb_type_rr_node_graph[pin_index].outedges[0] = new t_lb_type_rr_node_edge[1];
320	                lb_type_rr_node_graph[pin_index].outedges[0][0] = t_lb_type_rr_node_edge();
321	                lb_type_rr_node_graph[pin_index].outedges[0][0].intrinsic_cost = 1;
322	                lb_type_rr_node_graph[pin_index].type = LB_INTERMEDIATE;
323	                lb_type_rr_node_graph[pin_index].pb_graph_pin = pb_pin;
324	
325	                if (port_equivalent == PortEquivalence::NONE || sink_index == UNDEFINED) {
326	                    /* Create new sink for input to primitive */
327	                    t_lb_type_rr_node new_sink;
328	                    if (port_equivalent != PortEquivalence::NONE) {
329	                        new_sink.capacity = pb_pin->port->num_pins;
330	                    } else {
331	                        new_sink.capacity = 1;
332	                    }
333	                    new_sink.num_fanout = new short[1];
334	                    new_sink.num_fanout[0] = 0;
335	                    new_sink.type = LB_SINK;
336	                    sink_index = lb_type_rr_node_graph.size();
337	                    lb_type_rr_node_graph.push_back(new_sink);
338	                }
339	                lb_type_rr_node_graph[pin_index].outedges[0][0].node_index = sink_index;
340	            }
341	        }
342	
343	        /* alloc and load output pins that are represented as rr sources */
344	        for (int iport = 0; iport < pb_graph_node->num_output_ports; iport++) {
345	            for (int ipin = 0; ipin < pb_graph_node->num_output_pins[iport]; ipin++) {
346	                /* load intermediate indices */
347	                pb_pin = &pb_graph_node->output_pins[iport][ipin];
348	                pin_index = pb_pin->pin_count_in_cluster;
349	                num_modes = parent_node->pb_type->num_modes;
350	
351	                /* alloc and load rr node info */
352	                lb_type_rr_node_graph[pin_index].capacity = 1;
353	                lb_type_rr_node_graph[pin_index].num_modes = num_modes;
354	                lb_type_rr_node_graph[pin_index].num_fanout = new short[num_modes];
355	                lb_type_rr_node_graph[pin_index].outedges = new t_lb_type_rr_node_edge*[num_modes];
356	                for (int i = 0; i < num_modes; i++) {
357	                    lb_type_rr_node_graph[pin_index].outedges[i] = nullptr;
358	                    lb_type_rr_node_graph[pin_index].num_fanout[i] = 0;
359	                }
360	                lb_type_rr_node_graph[pin_index].pb_graph_pin = pb_pin;
361	
362	                /* Count number of mode-dependant fanout */
363	                for (int iedge = 0; iedge < pb_pin->num_output_edges; iedge++) {
364	                    VTR_ASSERT(pb_pin->output_edges[iedge]->num_output_pins == 1);
365	                    int pmode;
366	                    pmode = pb_pin->output_edges[iedge]->interconnect->parent_mode->index;
367	                    lb_type_rr_node_graph[pin_index].num_fanout[pmode]++;
368	                }
369	
370	                /* Allocate space based on fanout */
371	                for (int imode = 0; imode < num_modes; imode++) {
372	                    lb_type_rr_node_graph[pin_index].outedges[imode] = new t_lb_type_rr_node_edge[lb_type_rr_node_graph[pin_index].num_fanout[imode]];
373	                    for (int i = 0; i < lb_type_rr_node_graph[pin_index].num_fanout[imode]; i++)
374	                        lb_type_rr_node_graph[pin_index].outedges[imode][i] = t_lb_type_rr_node_edge();
375	                    lb_type_rr_node_graph[pin_index].num_fanout[imode] = 0; /* reset to 0 so that we can reuse this variable to populate fanout stats */
376	                }
377	
378	                /* Load edges */
379	                for (int iedge = 0; iedge < pb_pin->num_output_edges; iedge++) {
380	                    VTR_ASSERT(pb_pin->output_edges[iedge]->num_output_pins == 1);
381	                    int pmode;
382	                    int ioutedges;
383	                    pmode = pb_pin->output_edges[iedge]->interconnect->parent_mode->index;
384	                    ioutedges = lb_type_rr_node_graph[pin_index].num_fanout[pmode];
385	                    lb_type_rr_node_graph[pin_index].outedges[pmode][ioutedges].node_index = pb_pin->output_edges[iedge]->output_pins[0]->pin_count_in_cluster;
386	                    lb_type_rr_node_graph[pin_index].outedges[pmode][ioutedges].intrinsic_cost = get_cost_of_pb_edge(pb_pin->output_edges[iedge]);
387	                    lb_type_rr_node_graph[pin_index].num_fanout[pmode]++;
388	                }
389	
390	                lb_type_rr_node_graph[pin_index].type = LB_SOURCE;
391	            }
392	        }
393	
394	        /* alloc and load clock pins that connect to sinks */
395	        for (int iport = 0; iport < pb_graph_node->num_clock_ports; iport++) {
396	            PortEquivalence port_equivalent = PortEquivalence::NONE;
397	            int sink_index = UNDEFINED;
398	            for (int ipin = 0; ipin < pb_graph_node->num_clock_pins[iport]; ipin++) {
399	                /* load intermediate indices */
400	                pb_pin = &pb_graph_node->clock_pins[iport][ipin];
401	                port_equivalent = pb_pin->port->equivalent;
402	                pin_index = pb_pin->pin_count_in_cluster;
403	
404	                /* alloc and load rr node info */
405	                lb_type_rr_node_graph[pin_index].capacity = 1;
406	                lb_type_rr_node_graph[pin_index].num_modes = 1;
407	                lb_type_rr_node_graph[pin_index].num_fanout = new short[1];
408	                lb_type_rr_node_graph[pin_index].num_fanout[0] = 1;
409	                lb_type_rr_node_graph[pin_index].outedges = new t_lb_type_rr_node_edge*[1];
410	                lb_type_rr_node_graph[pin_index].outedges[0] = new t_lb_type_rr_node_edge[1];
411	                lb_type_rr_node_graph[pin_index].outedges[0][0].intrinsic_cost = 1;
412	                lb_type_rr_node_graph[pin_index].type = LB_INTERMEDIATE;
413	                lb_type_rr_node_graph[pin_index].pb_graph_pin = pb_pin;
414	
415	                if (port_equivalent == PortEquivalence::NONE || sink_index == UNDEFINED) {
416	                    /* Create new sink for clock to primitive */
417	                    t_lb_type_rr_node new_sink;
418	                    if (port_equivalent != PortEquivalence::NONE) {
419	                        new_sink.capacity = pb_pin->port->num_pins;
420	                    } else {
421	                        new_sink.capacity = 1;
422	                    }
423	                    new_sink.num_fanout = new short[1];
424	                    new_sink.num_fanout[0] = 0;
425	                    new_sink.type = LB_SINK;
426	                    sink_index = lb_type_rr_node_graph.size();
427	                    lb_type_rr_node_graph.push_back(new_sink);
428	                }
429	                lb_type_rr_node_graph[pin_index].outedges[0][0].node_index = sink_index;
430	            }
431	        }
432	    } else {
433	        /* This pb_graph_node is a logic block or subcluster */
434	        for (int imode = 0; imode < pb_type->num_modes; imode++) {
435	            for (int ipb_type = 0; ipb_type < pb_type->modes[imode].num_pb_type_children; ipb_type++) {
436	                for (int ipb = 0; ipb < pb_type->modes[imode].pb_type_children[ipb_type].num_pb; ipb++) {
437	                    alloc_and_load_lb_type_rr_graph_for_pb_graph_node(&pb_graph_node->child_pb_graph_nodes[imode][ipb_type][ipb], lb_type_rr_node_graph, ext_rr_index);
