1206	e_block_pack_status ClusterLegalizer::try_pack_molecule(PackMoleculeId molecule_id,
1207	                                                        LegalizationCluster& cluster,
1208	                                                        LegalizationClusterId cluster_id,
1209	                                                        const t_ext_pin_util& max_external_pin_util) {
1210	    // Try to pack the molecule into a cluster with this pb type.
1211	
1212	    // Safety debugs.
1213	    VTR_ASSERT_DEBUG(molecule_id.is_valid());
1214	    VTR_ASSERT_DEBUG(cluster.pb != nullptr);
1215	    VTR_ASSERT_DEBUG(cluster.type != nullptr);
1216	
1217	    // TODO: Remove these global accesses to the contexts.
1218	    // AtomContext used for:
1219	    //  - printing verbose statements
1220	    //  - Looking up the primitive pb
1221	    const AtomContext& atom_ctx = g_vpr_ctx.atom();
1222	    // FloorplanningContext used for:
1223	    //  - Checking if the atom can be placed in the cluster for floorplanning
1224	    //    constraints.
1225	    const FloorplanningContext& floorplanning_ctx = g_vpr_ctx.floorplanning();
1226	
1227	    const LogicalModels& models = g_vpr_ctx.device().arch->models;
1228	
1229	    // Get the molecule object.
1230	    const t_pack_molecule& molecule = prepacker_.get_molecule(molecule_id);
1231	
1232	    if (log_verbosity_ > 3) {
1233	        AtomBlockId root_atom = molecule.atom_block_ids[molecule.root];
1234	        VTR_LOG("\t\tTry pack molecule: '%s' (%s)",
1235	                atom_ctx.netlist().block_name(root_atom).c_str(),
1236	                models.model_name(atom_ctx.netlist().block_model(root_atom)).c_str());
1237	        VTR_LOGV(molecule.pack_pattern,
1238	                 " molecule_type %s molecule_size %zu",
1239	                 molecule.pack_pattern->name,
1240	                 molecule.atom_block_ids.size());
1241	        VTR_LOG("\n");
1242	    }
1243	
1244	    // if this cluster has a molecule placed in it that is part of a long chain
1245	    // (a chain that consists of more than one molecule), don't allow more long chain
1246	    // molecules to be placed in this cluster. To avoid possibly creating cluster level
1247	    // blocks that have incompatible placement constraints or form very long placement
1248	    // macros that limit placement flexibility.
1249	    if (cluster.placement_stats->has_long_chain && molecule.is_chain() && prepacker_.get_molecule_chain_info(molecule.chain_id).is_long_chain) {
1250	        VTR_LOGV(log_verbosity_ > 4, "\t\t\tFAILED Placement Feasibility Filter: Only one long chain per cluster is allowed\n");
1251	        VTR_LOGV(log_verbosity_ > 2, "\t\tFAILED pack molecule reason: long_chain_conflict\n");
1252	        return e_block_pack_status::BLK_FAILED_FEASIBLE;
1253	    }
1254	
1255	    // Check if every atom in the molecule is legal in the cluster from a
1256	    // floorplanning perspective
1257	    bool cluster_pr_update_check = false;
1258	    PartitionRegion new_cluster_pr = cluster.pr;
1259	    // TODO: This can be made more efficient by pre-computing the intersection
1260	    //       of all the atoms' PRs in the molecule.
1261	    for (AtomBlockId atom_blk_id : molecule.atom_block_ids) {
1262	        if (!atom_blk_id.is_valid())
1263	            continue;
1264	
1265	        // Try to intersect with atom PartitionRegion if atom exists
1266	        bool cluster_pr_needs_update = false;
1267	        bool block_pack_floorplan_status = check_cluster_floorplanning(atom_blk_id,
1268	                                                                       new_cluster_pr,
1269	                                                                       cluster.type,
1270	                                                                       floorplanning_ctx.constraints,
1271	                                                                       log_verbosity_,
1272	                                                                       cluster_pr_needs_update);
1273	        if (!block_pack_floorplan_status) {
1274	            VTR_LOGV(log_verbosity_ > 2, "\t\tFAILED pack molecule reason: floorplanning_conflict (atom '%s')\n",
1275	                     atom_ctx.netlist().block_name(atom_blk_id).c_str());
1276	            return e_block_pack_status::BLK_FAILED_FLOORPLANNING;
1277	        }
1278	
1279	        if (cluster_pr_needs_update) {
1280	            cluster_pr_update_check = true;
1281	        }
1282	    }
1283	
1284	    // Check if all atoms in the molecule can be added to the cluster without
1285	    // NoC group conflicts
1286	    NocGroupId new_cluster_noc_grp_id = cluster.noc_grp_id;
1287	    for (AtomBlockId atom_blk_id : molecule.atom_block_ids) {
1288	        if (!atom_blk_id.is_valid())
1289	            continue;
1290	
1291	        bool block_pack_noc_grp_status = check_cluster_noc_group(atom_blk_id,
1292	                                                                 new_cluster_noc_grp_id,
1293	                                                                 atom_noc_grp_id_,
1294	                                                                 log_verbosity_);
1295	        if (!block_pack_noc_grp_status) {
1296	            VTR_LOGV(log_verbosity_ > 2, "\t\tFAILED pack molecule reason: noc_group_conflict (atom '%s')\n",
1297	                     atom_ctx.netlist().block_name(atom_blk_id).c_str());
1298	            return e_block_pack_status::BLK_FAILED_NOC_GROUP;
1299	        }
1300	    }
1301	
1302	    std::vector<t_pb_graph_node*> primitives_list(max_molecule_size_, nullptr);
1303	    e_block_pack_status block_pack_status = e_block_pack_status::BLK_STATUS_UNDEFINED;
1304	    LazyPopUniquePriorityQueue<t_pb_graph_node*, std::tuple<float, int, int>> primitives_alive = build_primitive_candidate_queue(cluster.placement_stats,
1305	                                                                                                                                 molecule_id,
1306	                                                                                                                                 primitives_list,
1307	                                                                                                                                 prepacker_);
1308	
1309	    while (block_pack_status != e_block_pack_status::BLK_PASSED) {
1310	        if (primitives_alive.empty()) {
1311	            VTR_LOGV(log_verbosity_ > 3, "\t\tFAILED No candidate primitives available\n");
1312	            block_pack_status = e_block_pack_status::BLK_FAILED_FEASIBLE;
1313	            break; /* no more candidate primitives available, this molecule will not pack, return fail */
1314	        }
1315	
1316	        std::pair<t_pb_graph_node*, std::tuple<float, int, int>> primitive = primitives_alive.pop();
1317	        t_pb_graph_node* root = primitive.first;
1318	
1319	        if (!try_start_root_placement(cluster.placement_stats, molecule_id, root, primitives_list, prepacker_))
1320	            continue;
1321	
1322	        block_pack_status = e_block_pack_status::BLK_PASSED;
1323	        size_t failed_location = 0;
1324	        for (size_t i_mol = 0; i_mol < molecule.atom_block_ids.size() && block_pack_status == e_block_pack_status::BLK_PASSED; i_mol++) {
1325	            VTR_ASSERT((primitives_list[i_mol] == nullptr) == (!molecule.atom_block_ids[i_mol]));
1326	            failed_location = i_mol + 1;
1327	            AtomBlockId atom_blk_id = molecule.atom_block_ids[i_mol];
1328	            if (!atom_blk_id.is_valid())
1329	                continue;
1330	            // NOTE: This parent variable is only used in the recursion of this
1331	            //       function.
1332	            t_pb* parent = nullptr;
1333	            block_pack_status = try_place_atom_block_rec(primitives_list[i_mol],
1334	                                                         atom_blk_id,
1335	                                                         cluster.pb,
1336	                                                         &parent,
1337	                                                         cluster_id,
1338	                                                         atom_cluster_,
1339	                                                         molecule_id,
1340	                                                         cluster.cluster_router,
1341	                                                         log_verbosity_,
1342	                                                         prepacker_,
1343	                                                         clustering_chain_info_,
1344	                                                         mutable_atom_pb_lookup());
1345	        }
1346	
1347	        // This flag controls the pop_back cleanup of cluster.molecules in case of subsequent failure.
1348	        bool candidate_molecule_added_to_cluster = false;
1349	
1350	        if (block_pack_status == e_block_pack_status::BLK_PASSED) {
1351	            cluster.molecules.push_back(molecule_id);
1352	            candidate_molecule_added_to_cluster = true;
1353	
1354	            if (enable_pin_feasibility_filter_) {
1355	                // try_update_lookahead_pins_used requires the candidate molecule to
1356	                // already be in cluster.molecules, which is satisfied by the push above.
1357	                reset_lookahead_pins_used(cluster.pb);
1358	                try_update_lookahead_pins_used(cluster, prepacker_, atom_cluster_, atom_pb_lookup());
1359	                if (!check_lookahead_pins_used(cluster.pb, max_external_pin_util)) {
1360	                    VTR_LOGV(log_verbosity_ > 4, "\t\t\tFAILED Pin Feasibility Filter\n");
1361	                    block_pack_status = e_block_pack_status::BLK_FAILED_FEASIBLE;
1362	                } else {
1363	                    VTR_LOGV(log_verbosity_ > 3, "\t\t\tPin Feasibility: Passed pin feasibility filter\n");
1364	                }
1365	            }
1366	        }
1367	
1368	        // Before any of the nodes corresponding to the new molecule are added
1369	        // to the PST, mark the current cursor and bookkeeping state of our
1370	        // traversal through the PST as a "checkpoint". If the new molecule
1371	        // makes the cluster illegal and needs to be removed, we can reset the
1372	        // traversal state back to its position before the molecule was added.
1373	        // The nodes that were added to the PST for the illegal molecule will
1374	        // stay put, so if that path is traversed again, the molecule can be
1375	        // recognized as illegal without the need to run routing again.
1376	        if (packing_signature_tree_) {
1377	            packing_signature_tree_->set_checkpoint();
1378	        }
1379	
1380	        if (block_pack_status == e_block_pack_status::BLK_PASSED) {
1381	            /*
1382	             * during the clustering step of `do_clustering`, `detailed_routing_stage` is incremented at each iteration until it a cluster
1383	             * is correctly generated or `detailed_routing_stage` assumes an invalid value (E_DETAILED_ROUTE_INVALID).
1384	             * depending on its value we have different behaviors:
1385	             *  - E_DETAILED_ROUTE_AT_END_ONLY: Skip routing if heuristic is to route at the end of packing complex block.
1386	             *  - E_DETAILED_ROUTE_FOR_EACH_ATOM: Try to route if heuristic is to route for every atom. If the clusterer arrives at this stage,
1387	             *                                    it means that more checks have to be performed as the previous stage failed to generate a new cluster.
1388	             *
1389	             * mode_status is a data structure containing the status of the mode selection. Its members are:
1390	             *  - bool is_mode_conflict
1391	             *  - bool try_expand_all_modes
1392	             *  - bool expand_all_modes
1393	             *
1394	             * is_mode_conflict affects this stage. Its value determines whether the cluster failed to pack after a mode conflict issue.
1395	             * It holds a flag that is used to verify whether try_intra_lb_route ended in a mode conflict issue.
1396	             *
1397	             * Until is_mode_conflict is set to FALSE by try_intra_lb_route, the loop re-iterates. If all the available modes are exhausted
1398	             * an error will be thrown during mode conflicts checks (this to prevent infinite loops).
1399	             *
1400	             * If the value is TRUE the cluster has to be re-routed, and its internal pb_graph_nodes will have more restrict choices
1401	             * for what regards the mode that has to be selected.
1402	             *
1403	             * is_mode_conflict is initially set to TRUE, and, unless a mode conflict is found, it is set to false in `try_intra_lb_route`.
1404	             *
1405	             * try_expand_all_modes is set if the node expansion failed to find a valid routing path. The clusterer tries to find another route
1406	             * by using all the modes during node expansion.
1407	             *
1408	             * expand_all_modes is used to enable the expansion of all the nodes using all the possible modes.
1409	             */
1410	
1411	            // The pin counting legality check has passed, so now add LCNs
1412	            // corresponding to the new molecule atoms to the PST.
1413	            //
1414	            // The PST does not store nodes for molecules that fail pin
1415	            // counting since these arrangements are already known to be
1416	            // illegal without needing to run a costly routing check.
1417	            if (packing_signature_tree_) {
1418	                for (size_t i = 0; i < molecule.atom_block_ids.size(); i++) {
1419	                    AtomBlockId atom_block_id = molecule.atom_block_ids[i];
1420	                    if (atom_block_id) {
1421	                        packing_signature_tree_->add_lcn(primitives_list[i], atom_block_id);
1422	                    }
1423	                }
1424	            }
1425	
1426	            // Determine whether a legal routing exists for this cluster.
1427	            t_mode_selection_status mode_status;
1428	            e_ecn_legality legality = e_ecn_legality::UNKNOWN;
1429	            bool do_detailed_routing_stage = (cluster_legalization_strategy_ == ClusterLegalizationStrategy::FULL);
1430	            if (do_detailed_routing_stage) {
1431	                if (packing_signature_tree_) {
1432	                    // Query the PST to see if this cluster pattern has been seen
1433	                    // before, and if so, whether the routing legality is known.
1434	                    legality = packing_signature_tree_->check_legality();
1435

