444	bool ClusterRouter::try_intra_lb_route(int verbosity,
445	                                       t_mode_selection_status* mode_status) {
446	    VTR_ASSERT_MSG(!is_clean_ && is_valid_, "Cannot operate on a cleaned / invalid router.");
447	    bool is_routed = false;
448	    bool is_impossible = false;
449	
450	    mode_status->is_mode_conflict = false;
451	    mode_status->try_expand_all_modes = false;
452	
453	    t_expansion_node exp_node;
454	
455	    reset_explored_node_tb_();
456	
457	    /* Reset current routing */
458	    for (size_t inet = 0; inet < intra_lb_nets_.size(); inet++) {
459	        reset_lb_net_rt(intra_lb_nets_[inet].rt_tree);
460	    }
461	    for (size_t inode = 0; inode < lb_type_graph_->size(); inode++) {
462	        lb_rr_node_stats_[inode].historical_usage = 0;
463	        lb_rr_node_stats_[inode].occ = 0;
464	    }
465	
466	    std::unordered_map<const t_pb_graph_node*, const t_mode*> mode_map;
467	
468	    // Hot-start: seed previously-saved, still-valid route trees so that
469	    // pathfinder can skip unchanged nets on its first iteration.
470	    if (enable_hot_start_ && !saved_lb_nets_.empty())
471	        hot_start_intra_lb_route_(mode_map, mode_status);
472	
473	    /*	Iteratively remove congestion until a successful route is found.
474	     * Cap the total number of iterations tried so that if a solution does not exist, then the router won't run indefinitely */
475	    pres_con_fac_ = params_.pres_fac;
476	    for (int iter = 0; iter < params_.max_iterations && !is_routed && !is_impossible; iter++) {
477	        size_t inet;
478	        /* Iterate across all nets internal to logic block */
479	        for (inet = 0; inet < intra_lb_nets_.size() && !is_impossible; inet++) {
480	            int idx = inet;
481	            if (intra_lb_nets_[idx].rt_tree.current_node != UNDEFINED && is_skip_route_net(intra_lb_nets_[idx].rt_tree, *lb_type_graph_, lb_rr_node_stats_)) {
482	                continue;
483	            }
484	            if (intra_lb_nets_[idx].rt_tree.current_node != UNDEFINED) {
485	                commit_remove_rt_(intra_lb_nets_[idx].rt_tree, RT_REMOVE, mode_map, mode_status);
486	            }
487	            reset_lb_net_rt(intra_lb_nets_[idx].rt_tree);
488	            add_source_to_rt_(idx);
489	
490	            /* Route each sink of net */
491	            for (size_t itarget = 1; itarget < intra_lb_nets_[idx].terminals.size() && !is_impossible; itarget++) {
492	                pq_.clear();
493	                /* Get lowest cost next node, repeat until a path is found or if it is impossible to route */
494	
495	                expand_rt_(idx);
496	
497	                is_impossible = try_expand_nodes_(intra_lb_nets_[idx], &exp_node, itarget, mode_status->expand_all_modes, verbosity);
498	
499	                if (is_impossible && !mode_status->expand_all_modes) {
500	                    mode_status->try_expand_all_modes = true;
501	                    mode_status->expand_all_modes = true;
502	                    break;
503	                }
504	
505	                if (exp_node.node_index == intra_lb_nets_[idx].terminals[itarget]) {
506	                    /* Net terminal is routed, add this to the route tree, clear data structures, and keep going */
507	                    is_impossible = add_to_rt_(intra_lb_nets_[idx].rt_tree, exp_node.node_index, idx);
508	                }
509	
510	                if (verbosity > 5) {
511	                    VTR_LOG("Routing finished\n");
512	                    VTR_LOG("\tS");
513	                    print_trace_(stdout, intra_lb_nets_[idx].rt_tree);
514	                    VTR_LOG("\n");
515	                }
516	
517	                if (is_impossible) {
518	                    VTR_LOGV(verbosity > 5, "Routing was impossible!\n");
519	                } else if (mode_status->expand_all_modes) {
520	                    is_impossible = route_has_conflict(intra_lb_nets_[idx].rt_tree, *lb_type_graph_);
521	                    if (is_impossible) {
522	                        VTR_LOGV(verbosity > 5, "Routing was impossible due to modes!\n");
523	                    }
524	                }
525	
526	                explore_id_index_++;
527	                if (explore_id_index_ > 2000000000) {
528	                    /* overflow protection */
529	                    for (size_t id = 0; id < lb_type_graph_->size(); id++) {
530	                        explored_node_tb_[id].explored_id = UNDEFINED;
531	                        explored_node_tb_[id].enqueue_id = UNDEFINED;
532	                    }
533	                    explore_id_index_ = 1;
534	                }
535	            }
536	
537	            if (!is_impossible) {
538	                VTR_ASSERT(intra_lb_nets_[idx].rt_tree.current_node != UNDEFINED);
539	                commit_remove_rt_(intra_lb_nets_[idx].rt_tree, RT_COMMIT, mode_map, mode_status);
540	                if (mode_status->is_mode_conflict) {
541	                    is_impossible = true;
542	                }
543	            }
544	        }
545	
546	        if (!is_impossible) {
547	            is_routed = is_route_success_();
548	        } else {
549	            --inet;
550	            auto& atom_ctx = g_vpr_ctx.atom();
551	            VTR_LOGV(verbosity > 3, "Net '%s' is impossible to route within proposed %s cluster\n",
552	                     atom_ctx.netlist().net_name(intra_lb_nets_[inet].atom_net_id).c_str(), lb_type_->name.c_str());
553	            is_routed = false;
554	        }
555	        pres_con_fac_ *= params_.pres_fac_mult;
556	    }
557	
558	    if (is_routed) {
559	        save_and_reset_lb_route_();
560	    } else {
561	        //Unroutable
562	#ifdef PRINT_INTRA_LB_ROUTE
563	        print_route_(getEchoFileName(E_ECHO_INTRA_LB_FAILED_ROUTE));
564	#endif
565	
566	        if (verbosity > 3 && !is_impossible) {
567	            //Report the congested nodes and associated nets
568	            auto congested_rr_nodes = find_congested_rr_nodes(*lb_type_graph_, lb_rr_node_stats_);
569	            if (!congested_rr_nodes.empty()) {
570	                VTR_LOG("%s\n", describe_congested_rr_nodes_(congested_rr_nodes).c_str());
571	            }
