1950	bool ClusterLegalizer::is_molecule_compatible(PackMoleculeId molecule_id,
1951	                                              LegalizationClusterId cluster_id) const {
1952	    VTR_ASSERT_SAFE(molecule_id.is_valid());
1953	    VTR_ASSERT_SAFE(cluster_id.is_valid() && (size_t)cluster_id < legalization_clusters_.size());
1954	    // Go through each atom in the molecule and check if there exists a free
1955	    // primitive for that atom block.
1956	    // TODO: This should probably also check if there are enough free primitives
1957	    //       to support the given molecule. For example, a molecule of two FFs,
1958	    //       but the cluster only has one free FF. This was something that Jason
1959	    //       Luu was debating. Checking if placement exists for full molecule
1960	    //       would be more robust, but checking individual atoms is faster.
1961	    const LegalizationCluster& cluster = legalization_clusters_[cluster_id];
1962	
1963	    const t_pack_molecule& molecule = prepacker_.get_molecule(molecule_id);
1964	    for (AtomBlockId atom_blk_id : molecule.atom_block_ids) {
1965	        // FIXME: Why is it possible that molecules contain invalid block IDs?
1966	        //        This should be fixed!
1967	        if (!atom_blk_id.is_valid())
1968	            continue;
